import{_ as e,o as a,c as i,a as n}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"4.5  基于 Kprobe 的事件跟踪——内部细节","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch04_5.md","filePath":"notes/linux_kernel_debugging/ch04_5.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch04_5.md"};function l(p,s,r,o,h,c){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="_4-5-基于-kprobe-的事件跟踪——内部细节" tabindex="-1">4.5 基于 Kprobe 的事件跟踪——内部细节 <a class="header-anchor" href="#_4-5-基于-kprobe-的事件跟踪——内部细节" aria-label="Permalink to &quot;4.5  基于 Kprobe 的事件跟踪——内部细节&quot;">​</a></h1><p>还记得上一节结尾留下的那个念想吗？有没有一种办法，不用写一行 C 代码，不用编译内核模块，就能给内核里的任意函数「装个窃听器」？</p><p>答案是肯定的，而且这个办法比你想象的要近得多。它就藏在你平时可能路过的 <code>/sys/kernel/debug/tracing</code> 目录里。</p><p>这个机制叫 <strong>kprobe-based event tracing</strong>（基于 kprobe 的事件跟踪）。</p><h3 id="这一节本质上在讲什么" tabindex="-1">这一节本质上在讲什么 <a class="header-anchor" href="#这一节本质上在讲什么" aria-label="Permalink to &quot;这一节本质上在讲什么&quot;">​</a></h3><p>这一节表面上是在教你怎么用 tracefs 文件系统，实际上是在揭示 <code>perf</code> 和 <code>eBPF</code> 这些高级工具背后的「降维打击」手段。当你运行一个复杂的 perf 脚本时，它本质上就是在这一节要讲的文件系统里写写画画。</p><p>让我们揭开这层幕布。</p><hr><h3 id="事件跟踪框架的真相" tabindex="-1">事件跟踪框架的真相 <a class="header-anchor" href="#事件跟踪框架的真相" aria-label="Permalink to &quot;事件跟踪框架的真相&quot;">​</a></h3><p>当你运行 <code>perf probe</code> 或者那些自动化脚本时，你以为它们在搞什么黑魔法，其实它们只是在做一件非常机械的事情：利用内核的 <strong>ftrace 基础设施</strong> 来注册探针。</p><p>你可能注意到了，上一节我们查看 <code>/sys/kernel/debug/kprobes/list</code> 时，右边有一列 <code>[FTRACE]</code>。现在这个谜题解开了：kprobe 的底层实现，有一部分是借用了 ftrace 的机制。</p><p>在这个框架里，有一块专门叫 <strong>kprobe events</strong>，它是 ftrace 大系统的一个子集。它的核心思想是把「探针」抽象成「事件」。你定义一个事件，内核帮你把探针挂上去，然后把数据收集到统一的 trace buffer 里。</p><hr><h3 id="在事件跟踪框架下追踪内置函数" tabindex="-1">在事件跟踪框架下追踪内置函数 <a class="header-anchor" href="#在事件跟踪框架下追踪内置函数" aria-label="Permalink to &quot;在事件跟踪框架下追踪内置函数&quot;">​</a></h3><p>一切的前提是内核开启了 <code>CONFIG_KPROBE_EVENTS=y</code>。好消息是，大部分发行版内核，哪怕是生产环境的，默认都开了这个。</p><p>让我们潜入那个目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/kernel/tracing/events</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里有一堆文件夹，代表了内核里各种子系统已经暴露出来的「事件类」。</p><blockquote><p><strong>一个小小的路径问题</strong></p><p>你可能会看到 <code>/sys/kernel/debug/tracing</code> 和 <code>/sys/kernel/tracing</code> 两个路径。 其实它们通常指向同一个东西。有时候生产环境为了安全会把 <code>debugfs</code> 给挂掉不让人看，但 <code>tracefs</code> (<code>/sys/kernel/tracing</code>) 往往还是留着给性能工具用的。 后面我们为了通顺，统称为 <code>&lt;tracing&gt;</code>。</p></blockquote><p>看看下面这张图，感受一下这棵树的繁茂程度：</p><p><em>(📷 Figure 4.10 – Screenshot showing the kernel&#39;s event tracing - pseudo files and folders)</em></p><p>这里面全是现成的。</p><h4 id="来试一个-kmalloc" tabindex="-1">来试一个：kmalloc <a class="header-anchor" href="#来试一个-kmalloc" aria-label="Permalink to &quot;来试一个：kmalloc&quot;">​</a></h4><p>拿最常用的内存分配函数 <code>kmalloc</code> 开刀。在图 4.10 的底部，你能看到 <code>events/kmem/kmalloc</code> 这个目录。这就是内核帮你预置好的监控点。</p><p>不需要写代码，只需要：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 打开监控</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tracin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/events/kmem/kmalloc/enable</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看输出</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tracin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/trace_pipe</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>trace_pipe</code> 是个特殊的文件，它就像 <code>tail -f</code> 一样，数据流实时往外喷。而普通的 <code>trace</code> 文件是快照。</p><p>这时候，系统里任何一个模块调用 <code>kmalloc</code>，都会被记录下来。你会看到类似这样的输出刷屏：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;...&gt;-1234 [001] .... 12345.678901: kmalloc: call_site=ptr_spin_lock+0x4/0x20 ptr=ffff88000001 size=64 bytes_req=64 bytes_alloc=64 gfp_flags=GFP_KERNEL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的信息极其丰富：</p><ul><li>谁调用的 (<code>call_site</code>)</li><li>分配了多大 (<code>size</code>)</li><li>实际拿了多大 (<code>bytes_alloc</code>)</li><li>分配标志是什么 (<code>gfp_flags</code>)</li></ul><p>这些字段的格式定义，其实都在那个目录下的 <code>format</code> 伪文件里写着。<code>perf</code> 这些工具就是靠解析这个文件来知道怎么打印数据的。</p><h4 id="擦屁股" tabindex="-1">擦屁股 <a class="header-anchor" href="#擦屁股" aria-label="Permalink to &quot;擦屁股&quot;">​</a></h4><p>看完了，记得关掉，否则 trace buffer 会爆：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tracin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/events/kmem/kmalloc/enable</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">tracin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">g</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/trace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><em>(📷 Figure 4.11 – Truncated screenshot showing an example of easily tracing the kmalloc routine)</em></p><p>就这么简单。没有模块加载，没有 <code>printk</code>，没有内核崩溃风险。</p><hr><h3 id="好了-陷阱来了" tabindex="-1">好了，陷阱来了 <a class="header-anchor" href="#好了-陷阱来了" aria-label="Permalink to &quot;好了，陷阱来了&quot;">​</a></h3><p>这一节到目前为止，我们玩的是「现成的」——也就是内核开发者们好心帮你预先在代码里埋好的 <strong>Tracepoints</strong>。</p><p>图 4.10 里列出的那些目录，都是静态埋点。这就像你买了一栋带家具的房子，家具是开发商配好的。</p><p><strong>但现实往往是残酷的</strong>。</p><p>如果你想监控的那个函数——比如你自己写的内核模块里的某个函数，或者某个冷门内核函数——根本没出现在 <code>/sys/kernel/tracing/events</code> 目录下怎么办？</p><p>如果目录里没有，你就没法用上面的 <code>enable</code> 方法。</p><p>这就是下一节要解决的终极问题： <strong>当你面对的是一套没有埋点的「毛坯房」时，怎么动态地在墙上打洞？</strong></p><p>下一节，我们将进入真正的动态 kprobe 领域——没有现成的目录，一切都靠你自己创建。</p>`,46)])])}const g=e(t,[["render",l]]);export{k as __pageData,g as default};
